//! Router-level integration tests for the scan-planning surface
//! (planTableScan / fetchPlanningResult / cancelPlanning /
//! fetchScanTasks).
//!
//! These require a running Postgres and `DATABASE_URL`; without it they
//! skip (with a note on stderr). Every test provisions its own
//! uniquely-named warehouse rooted in its own tempdir (`file://`
//! storage) and registers fixture tables generated by
//! `meridian_bench::fixture` — real Avro manifests written by the
//! wave-one writers, so pruning and delete attachment are asserted
//! against ground truth, not mocks.

// The shared IdP fixture exposes more than this binary uses.
#[allow(dead_code)]
mod idp;

use std::collections::BTreeSet;
use std::sync::Arc;

use axum::Router;
use axum::body::Body;
use axum::http::{Request, StatusCode};
use http_body_util::BodyExt;
use idp::{AUDIENCE, KID1, TestIdp};
use meridian_bench::fixture::{self, SyntheticSpec};
use meridian_common::AppConfig;
use meridian_common::config::{AuthMode, OidcIssuerConfig};
use meridian_server::{AppState, build_router};
use meridian_store::tenancy;
