use sqlx::PgPool;
use tower::ServiceExt;
use ulid::Ulid;

struct TestCtx {
    router: Router,
    pool: PgPool,
    root: tempfile::TempDir,
    warehouse: String,
}

/// Connects, migrates, creates a tempdir-rooted warehouse, and builds a
/// router with `configure` applied to the config (planning knobs).
async fn test_ctx(configure: impl FnOnce(&mut AppConfig)) -> Option<TestCtx> {
    let Ok(url) = std::env::var("DATABASE_URL") else {
        eprintln!("skipping planning API test: DATABASE_URL is not set");
        return None;
    };

    let mut config = AppConfig::default();
    config.database.url = url;
    configure(&mut config);

    let pool = meridian_store::connect(&config.database)
        .await
        .expect("connect to test database");
    meridian_store::MIGRATOR
        .run(&pool)
        .await
        .expect("run migrations");

    let router = build_router(AppState {
        pool: pool.clone(),
        config: Arc::new(config),
    });

    let root = tempfile::tempdir().expect("create tempdir");
    let warehouse = format!("wh-plan-{}", Ulid::new().to_string().to_lowercase());
    let storage_root = format!("file://{}", root.path().join("warehouse").display());
    let (status, body) = send(
        &router,
        "POST",
        "/api/v2/warehouses",
        None,
        Some(&json!({ "name": warehouse, "storage_root": storage_root })),
    )
    .await;
    assert_eq!(status, StatusCode::CREATED, "create warehouse: {body}");

    Some(TestCtx {
        router,
        pool,
        root,
        warehouse,
    })
}

async fn send_with_token(
    router: &Router,
    method: &str,
    uri: &str,
    token: Option<&str>,
    body: Option<&Value>,
) -> (StatusCode, Value) {
    let mut builder = Request::builder().method(method).uri(uri);
    if let Some(token) = token {
        builder = builder.header("authorization", format!("Bearer {token}"));
    }
    let request = match body {
        Some(body) => builder
            .header("content-type", "application/json")
            .body(Body::from(body.to_string())),
        None => builder.body(Body::empty()),
    }
    .expect("build request");

    let response = router
        .clone()
        .oneshot(request)
        .await
        .expect("infallible router call");
    let status = response.status();
    let bytes = response
        .into_body()
        .collect()
        .await
        .expect("read body")
        .to_bytes();
    let value = if bytes.is_empty() {
        Value::Null
    } else {
        serde_json::from_slice(&bytes).expect("response body is JSON")
    };
    (status, value)
}

async fn send(
    router: &Router,
    method: &str,
    uri: &str,
    token: Option<&str>,
    body: Option<&Value>,
) -> (StatusCode, Value) {
    send_with_token(router, method, uri, token, body).await
}

fn assert_error(body: &Value, code: u16, error_type: &str) {
    assert_eq!(body["error"]["code"], code, "envelope: {body}");
    assert_eq!(body["error"]["type"], error_type, "envelope: {body}");
}

/// Writes a generated fixture into the warehouse tempdir and registers
/// it as `{ns}.{table}`. Returns the plan endpoint base URL.
async fn register_fixture(
    ctx: &TestCtx,
    ns: &str,
    table: &str,
    files: &[(String, Vec<u8>)],
    metadata_location: &str,
) -> String {
    fixture::write_local(files).expect("write fixture files");
    let (status, body) = send(
        &ctx.router,
        "POST",
        &format!("/v1/{}/namespaces", ctx.warehouse),
        None,
        Some(&json!({ "namespace": [ns] })),
    )
    .await;
    assert!(
        status == StatusCode::OK || status == StatusCode::CONFLICT,
        "create namespace: {body}"
    );
    let (status, body) = send(
        &ctx.router,
        "POST",
        &format!("/v1/{}/namespaces/{ns}/register", ctx.warehouse),
        None,
        Some(&json!({ "name": table, "metadata-location": metadata_location })),
    )
    .await;
    assert_eq!(status, StatusCode::OK, "register fixture table: {body}");
    format!("/v1/{}/namespaces/{ns}/tables/{table}", ctx.warehouse)
}

/// The fixture's table root inside this test's warehouse tempdir.
fn table_location(ctx: &TestCtx, ns: &str, table: &str) -> String {
    format!(
        "file://{}",
        ctx.root
            .path()
            .join("warehouse")
            .join(ns)
            .join(table)
            .display()
    )
}

fn task_paths(tasks: &Value) -> Vec<String> {
    tasks["file-scan-tasks"]
        .as_array()
        .expect("file-scan-tasks array")
        .iter()
        .map(|t| {
            t["data-file"]["file-path"]
                .as_str()
                .expect("file-path")
                .to_owned()
        })
        .collect()
}

/// Resolves each task's delete references to delete-file paths.
fn deletes_by_task(tasks: &Value) -> Vec<(String, BTreeSet<String>)> {
    let delete_paths: Vec<String> = tasks["delete-files"]
        .as_array()
        .map(|deletes| {
            deletes
                .iter()
                .map(|d| d["file-path"].as_str().expect("delete path").to_owned())
                .collect()
        })
        .unwrap_or_default();
    tasks["file-scan-tasks"]
        .as_array()
        .expect("file-scan-tasks array")
        .iter()
        .map(|t| {
            let path = t["data-file"]["file-path"]
                .as_str()
                .expect("path")
                .to_owned();
            let refs: BTreeSet<String> = t["delete-file-references"]
                .as_array()
                .map(|refs| {
                    refs.iter()
                        .map(|i| {
                            let i = usize::try_from(i.as_u64().expect("index")).expect("usize");
                            delete_paths[i].clone()
                        })
                        .collect()
                })
                .unwrap_or_default();
            (path, refs)
        })
        .collect()
}

